import{c as a,a7 as t,y as i,B as r}from"./chunks/framework.3cjvm90C.js";const k=JSON.parse('{"title":"Data Parallel Training","description":"PyTorch 数据并行训练（DDP）的原理与实践","frontmatter":{"title":"Data Parallel Training","description":"PyTorch 数据并行训练（DDP）的原理与实践"},"headers":[],"relativePath":"dlwiki/distributed-training/ddp.md","filePath":"dlwiki/distributed-training/ddp.md","lastUpdated":1782448598000}'),s={name:"dlwiki/distributed-training/ddp.md"};function l(n,e,o,h,d,p){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h2 id="data-parallel-training" tabindex="-1">Data Parallel Training <a class="header-anchor" href="#data-parallel-training" aria-label="Permalink to “Data Parallel Training”">​</a></h2><p>PyTorch provides several options for data-parallel training. For applications that gradually grow from simple to complex and from prototype to production, the common development trajectory would be:</p><ol><li>Use single-device training, if the data and model can fit in one GPU, and the training speed is not a concern.</li><li>Use single-machine multi-GPU <a href="https://pytorch.org/docs/master/generated/torch.nn.DataParallel.html" target="_blank" rel="noreferrer">DataParallel</a>, if there are multiple GPUs on the server, and you would like to speed up training with the minimum code change.</li><li>Use single-machine multi-GPU <a href="https://pytorch.org/docs/master/generated/torch.nn.parallel.DistributedDataParallel.html" target="_blank" rel="noreferrer">DistributedDataParallel</a>, if you would like to further speed up training and are willing to write a little more code to set it up.</li><li>Use multi-machine <a href="https://pytorch.org/docs/master/generated/torch.nn.parallel.DistributedDataParallel.html" target="_blank" rel="noreferrer">DistributedDataParallel</a> and the <a href="https://github.com/pytorch/examples/blob/master/distributed/ddp/README.md" target="_blank" rel="noreferrer">launching script</a>, if the application needs to scale across machine boundaries.</li><li>Use <a href="https://pytorch.org/elastic" target="_blank" rel="noreferrer">torchelastic</a> to launch distributed training, if errors (e.g., OOM) are expected or if the resources can join and leave dynamically during the training.</li></ol><h3 id="_1-torch-nn-dataparallel" tabindex="-1">1. torch.nn.DataParallel <a class="header-anchor" href="#_1-torch-nn-dataparallel" aria-label="Permalink to “1.  torch.nn.DataParallel”">​</a></h3><p>The <a href="https://pytorch.org/docs/master/generated/torch.nn.DataParallel.html" target="_blank" rel="noreferrer">DataParallel</a> package enables single-machine multi-GPU parallelism with the lowest coding hurdle. It only requires a one-line change to the application code. The tutorial <a href="https://pytorch.org/tutorials/beginner/blitz/data_parallel_tutorial.html" target="_blank" rel="noreferrer">Optional: Data Parallelism</a> shows an example. The caveat is that, although <code>DataParallel</code> is very easy to use, it usually does not offer the best performance. This is because the implementation of <code>DataParallel</code> replicates the model in every forward pass, and its single-process multi-thread parallelism naturally suffers from GIL contentions. To get better performance, please consider using <a href="https://pytorch.org/docs/master/generated/torch.nn.parallel.DistributedDataParallel.html" target="_blank" rel="noreferrer">DistributedDataParallel</a>.</p><h4 id="_1-1-torch-nn-dataparallel" tabindex="-1">1.1 torch.nn.DataParallel <a class="header-anchor" href="#_1-1-torch-nn-dataparallel" aria-label="Permalink to “1.1 torch.nn.DataParallel”">​</a></h4><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torch.nn.DataParallel(module, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">device_ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">None</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">output_device</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">None</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    Parameters</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    module (Module) – module to be parallelized</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    device_ids (list of python:int or torch.device) – CUDA devices (default: all devices)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    output_device (int or torch.device) – device location of output (default: device_ids[0])</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;&quot;&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Examples</p><div class="language-python line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;&gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> net </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> torch.nn.DataParallel(model, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">device_ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;&gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> output </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> net(input_var)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># input_var can be on any device, including CPU</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Implements data parallelism at the module level.</p><p>This container parallelizes the application of the given <code>module</code> by splitting the input across the specified devices by chunking in the batch dimension (other objects will be copied once per device). In the forward pass, the module is replicated on each device, and each replica handles a portion of the input. During the backwards pass, gradients from each replica are summed into the original module.</p><p>The batch size should be larger than the number of GPUs used.</p><p>Arbitrary positional and keyword inputs are allowed to be passed into DataParallel but some types are specially handled. tensors will be <strong>scattered</strong> on dim specified (default 0). tuple, list and dict types will be shallow copied. The other types will be shared among different threads and can be corrupted if written to in the model’s forward pass.</p><p>The parallelized <code>module</code> must have its parameters and buffers on <code>device_ids[0]</code> before running this <a href="https://pytorch.org/docs/master/generated/torch.nn.DataParallel.html#torch.nn.DataParallel" target="_blank" rel="noreferrer"><code>DataParallel</code></a> module.</p><h4 id="warning" tabindex="-1">WARNING <a class="header-anchor" href="#warning" aria-label="Permalink to “WARNING”">​</a></h4><blockquote><p>In each forward, <code>module</code> is <strong>replicated</strong> on each device, so any updates to the running module in <code>forward</code> will be lost. For example, if <code>module</code> has a counter attribute that is incremented in each <code>forward</code>, it will always stay at the initial value because the update is done on the replicas which are destroyed after <code>forward</code>. However, <a href="https://pytorch.org/docs/master/generated/torch.nn.DataParallel.html#torch.nn.DataParallel" target="_blank" rel="noreferrer"><code>DataParallel</code></a> guarantees that the replica on <code>device[0]</code> will have its parameters and buffers sharing storage with the base parallelized <code>module</code>. So <strong>in-place</strong> updates to the parameters or buffers on <code>device[0]</code> will be recorded. E.g., <a href="https://pytorch.org/docs/master/generated/torch.nn.BatchNorm2d.html#torch.nn.BatchNorm2d" target="_blank" rel="noreferrer"><code>BatchNorm2d</code></a> and <a href="https://pytorch.org/docs/master/generated/torch.nn.utils.spectral_norm.html#torch.nn.utils.spectral_norm" target="_blank" rel="noreferrer"><code>spectral_norm()</code></a> rely on this behavior to update the buffers.</p></blockquote><h4 id="warning-1" tabindex="-1">WARNING <a class="header-anchor" href="#warning-1" aria-label="Permalink to “WARNING”">​</a></h4><blockquote><p>Forward and backward hooks defined on <code>module</code> and its submodules will be invoked <code>len(device_ids)</code> times, each with inputs located on a particular device. Particularly, the hooks are only guaranteed to be executed in correct order with respect to operations on corresponding devices. For example, it is not guaranteed that hooks set via <a href="https://pytorch.org/docs/master/generated/torch.nn.Module.html#torch.nn.Module.register_forward_pre_hook" target="_blank" rel="noreferrer"><code>register_forward_pre_hook()</code></a> be executed before all <code>len(device_ids)</code> <a href="https://pytorch.org/docs/master/generated/torch.nn.Module.html#torch.nn.Module.forward" target="_blank" rel="noreferrer"><code>forward()</code></a> calls, but that each such hook be executed before the corresponding <a href="https://pytorch.org/docs/master/generated/torch.nn.Module.html#torch.nn.Module.forward" target="_blank" rel="noreferrer"><code>forward()</code></a> call of that device.</p></blockquote><p>Data Parallelism is when we split the mini-batch of samples into multiple smaller mini-batches and run the computation for each of the smaller mini-batches in parallel.</p><p>Data Parallelism is implemented using <code>torch.nn.DataParallel</code>. One can wrap a Module in <code>DataParallel</code> and it will be parallelized over multiple GPUs in the batch dimension.</p>`,20)])])}const g=a(s,[["render",l]]);export{k as __pageData,g as default};
